exercise.solution_code:
#include <iostream>
#include <iomanip>

namespace celsius {
    void display(double temp) {
        std::cout << std::fixed << std::setprecision(1);
        std::cout << "Celsius: " << temp << " C\n";
    }
}

namespace fahrenheit {
    void display(double temp) {
        std::cout << std::fixed << std::setprecision(1);
        std::cout << "Fahrenheit: " << temp << " F\n";
    }
}

int main() {
    double c, f;
    std::cin >> c >> f;

    celsius::display(c);
    fahrenheit::display(f);

    return 0;
}
